<template>
  <div id="carousel">
       <agile :speed="350" :timing="'linear'" :fade="true" :autoplay="true" :autoplaySpeed="5000" :pauseOnHover="true"> 
            <div class="slide slide--1">
              <img class="center hidden-xs" src="../../assets/img/intro/Intro-slide.png" alt="">
              <img class="center visible-xs" src="../../assets/img/intro/Intro-slide-mobile.png" alt="">
            </div>
            <div class="slide slide--2">
                  <h3 class="dailyVersesWrapper"></h3>
            </div>
            <div class="slide slide--3">
                <h3 class="dailyVersesWrapper2"></h3>
            </div>
            <div class="slide slide--4">
                <h3 class="dailyVersesWrapper3"></h3>
            </div>
            <div class="slide slide--5">
                <h3 class="dailyVersesWrapper4"></h3>
            </div>
       </agile>
  </div>
</template>

<script>
export default {
  name: 'carousel',
   data(){
      return{
          slide: 0,
          sliding: null
      }
  },
  methods: {
    onSlideStart (slide) {
      this.sliding = true
    },
    onSlideEnd (slide) {
      this.sliding = false
    },
      getVerses(){
          $(document).ready(function(){
          $.ajax({
               url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
               dataType: 'JSONP',
               success:function(json){
               $(".dailyVersesWrapper").prepend(json.html);
            }
            });
        $.ajax({
              url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
              dataType: 'JSONP',
              success:function(json){
               $(".dailyVersesWrapper2").prepend(json.html);
              }
           });
        $.ajax({
            url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
            dataType: 'JSONP',
            success:function(json){
             $(".dailyVersesWrapper3").prepend(json.html);
            }
         });
         $.ajax({
          url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
          dataType: 'JSONP',
          success:function(json){
           $(".dailyVersesWrapper4").prepend(json.html);
          }
        });
        $.ajax({
            url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
            dataType: 'JSONP',
            success:function(json){
            $(".dailyVersesWrapper5").prepend(json.html);
            }
        });
          });
      }
},
    mounted(){
        this.getVerses()
    }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';
@import '../../assets/bootstrap.min';


#carousel {
  // background: white;
  // width: 100vw;
  position: relative;
  top: -100vh;
  left: 0%;


}

.agile {
  position: absolute;
  top: 0px;
  left: 140px;
  right: 0;


}

.agile__track{
  width: 1000vw;
}


.slide {
  height: 100vh; 
  // background: red;
    h3 {
    width: 80%;
    padding-top: 10vw;
    padding-left: 7vw; 
    text-align: center;
    font-weight: 500;
    font-size: 6vh ;
    color: white;

  }
  img {
     position: relative;
      width: 100vw;
      left: 40%;
      top: 45%;
      margin-right: -50%;
       transform: translate(-50%, -50%);
   
    
  }
  a {
      color: #222 ;
      text-decoration: none;
      font-size: 4vh;
      float: right;

  }
}
    // .agile__track{
    //   width: 100vw!important;
    // }
  
    .agile__dot {
        margin-bottom: 10px;

        button {
            background-color: transparent;
            // border: 1px solid #fff;
            background: $grayb;
            margin-top: 10px;
            border-radius: 100%;
            height: 13px;
            transition: all .5s;
  

            &:hover {
                background-color: #fff;
            }
        }
    }

    .agile__dot--current {
            button {
                background-color: #222;
                transition: all .5s;
            }
        }


        @media screen and (max-width: 748px) {

            #carousel {
  // background: white;
  // width: 100vw;
  position: relative;
  top: -100vh;
  left: -5%;


}

.agile {
  position: absolute;
  top: 0px;
  left: 0px;
  right: 0;


}

.agile__track{
  width: 1000vw;
}


.slide {
  height: 100vh; 
  // background: red;
    h3 {
    width: 90%;
    padding-top: 30vw;
    left: 6vw;
    position: relative; 
    text-align: center;
    font-size: 3vh ;
    color: white;

  }
  img {
     position: relative;
      width: 89vw!important;
      height: 90vh;
      left: 55%!important;
      top: 51%!important;
      margin-right: -50%;
       transform: translate(-50%, -50%);
       border-radius: 10px;

  }

}
    // .agile__track{
    //   width: 100vw!important;
    // }
    .agile__dots {
        bottom: 5vh;
        display: block;
        right: 80vw;
        position: absolute;
        width: 30px;
    }
    .agile__dot {
        margin-bottom: 10px;

        button {
            background-color: transparent;
            // border: 1px solid #fff;
            background: $grayb;
            margin-top: 10px;
            border-radius: 100%;
            height: 13px;
            transition: all .5s;
  

            &:hover {
                background-color: #fff;
            }
        }
    }

    .agile__dot--current {
            button {
                background-color: #222;
                transition: all .5s;
            }
        }

        }

</style>



