<template>
  <div>
      <h1>DASHBOARD</h1>
      <button @click="logout()">Logout</button>
  </div>
</template>

<script>
import firebase from 'firebase';

export default {
  name: 'Dashboard',
  data(){
      return {
          isLoggedIn: false,
          currentUser: false
      }
  },
  methods:{
      logout(){
          firebase.auth().signOut().then(() => {
              this.$router.push('/miembros');
          })
      }
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

</style>



