<template>
   <div class="map">
       <loader/>
         <div class="overflow cont"><iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d612.9787608429226!2d-88.30471043801387!3d42.03886171615099!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x880f0516292058c7%3A0x46f7a2a8a950e784!2sChurch+of+Christ!5e1!3m2!1sen!2sus!4v1516216451285"  frameborder="0" style="border:0" allowfullscreen></iframe>   </div>
    </div>
</template>

<script>

import Loader from "../components/main/Loader.vue"

export default {
  name: 'Map',
  components: {
      "loader": Loader
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';
@import '../assets/bootstrap.min';

 .map {
        position: relative;
        height: 100vh;
        // background: $gradient-2;
    }
    .overflow {
        overflow: hidden!important;
    }
    .cont {
        display:none;
    }

    iframe{
        position: relative;
        float: right;
        height: 100vh;
        width: 92.5vw;
    }

    @media screen and (max-width: 748px) {

        iframe {
            width: 100vw;
        }
    }

</style>



