<template>
 <div id="gallery">


<loader/>

<div class="cont">


<div class="parallax hidden-xs"></div>

<div class="wrapper" > 
    <div class="masonry">
     <div v-for="(image, index) in output" :key="image" class="item">
        <img :src="image"  alt=""  class="v-img" @click="clickedImage(image); showingModal= true;"> 
        <div class ="centered" v-if="index % 2">{{image}}</div>
     </div>
      
    </div>
</div>

  <transition name="slide-fade">
               <div class="modalImage" id="addModal" v-if="showingModal" >
                <div class="modalContainerImages">
                    <div class="modalHeadingImage ">
                        <div class="closeImage" @click="showingModal = false;">
                            &times;
                        </div>
                        <div class="modalImages">
                            <img v-model="imageClicked" :src="imageClicked" alt="">
                        </div>
                    </div>
                </div>
            </div>
    </transition>
 </div>
 </div>
</template>

<script>
import json from '../assets/gallery/gallery.json';
import Loader from "../components/main/Loader.vue";

export default {
  name: 'Gallery',
  components:{
      "loader": Loader,
  },
  data(){
      return {
          gallery_images: "",
          showingModal: false,
          imageClicked: {},
          photoURL: {},
          output: {},

            show   : false, // display content after API request
            offset : 5,     // items to display after scroll
            display: 5,     // initial items
            trigger: 300,   // how far from the bottom to trigger infinite scroll
            end    : false, // no more resources

      }
  },
  computed: {
      // slice the array of data to display
      sliced() {
         return this.photoURL.slice(0, this.display);
      },
   },
  methods: {
      instaData: function(){

          var access_token = "efadf64726bd76295377877a5689a6dc";

                this.$http.get("https://api.flickr.com/services/rest/?&method=flickr.people.getPublicPhotos&api_key="+ access_token +"&user_id=139127837@N05&per_page=100&format=json&jsoncallback=?")
                    .then(response => {

                        var result = response.data.replace("jsonFlickrApi(", "").replace(')','');
                        var data = JSON.parse(result);
                        var photo = data.photos.photo;
                        var url = [];
                        var text = [];
                        var output = [];

                    
                        
                        for (var i = 0 ; i < photo.length; i++ ) {
                            
                            url.push('http://farm' + photo[i].farm + '.static.flickr.com/' + photo[i].server + '/' + photo[i].id + '_' + photo[i].secret + '_b.jpg');
                            text.push(photo[i].title);
                        }

                        var i
                         var l = Math.min(url.length, text.length);

                        for (i = 0; i < l; i++) {
                            output.push(url[i], text[i]);
                        }
                        output.push(...url.slice(l), ...text.slice(l));
            
                        this.output= output;




                    });

      },

      clickedImage(image){

          console.log(image)
          this.imageClicked = image;
      },
       scroll() {
           window.onscroll = ev => {
            if (
               window.innerHeight + window.scrollY >=
               (document.body.offsetHeight - this.trigger)
            ) {
               if (this.display < this.photoURL.length) {
                  this.display = this.display + this.offset;
               }
               else {
                  this.end = true;
               }
            }
         };
    },
     fetch() {
         window.setTimeout(() => {
            // example response data
            this.photoURL;
            this.show = true;
         }, 2000);
      }
},
mounted(){
    this.instaData();
    this.scroll();
   
},
created(){
    this.fetch();
}
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';
@import '../assets/bootstrap.min';

   #gallery {
        background: #222;
        margin-top: 50px;

        // .cont {
        //     // display:none;
        // }
        .insta-img {
                position: relative;
                z-index: 1;
        }

        // .cont {
        //     display: none;
        // }

        .parallax {
    background-image: url('../assets/img/intro/visitback.jpg');
    background-repeat: no-repeat;
    position: fixed;
    z-index: 0;
    left: 0;
    opacity: .2;
    top:0px;
    background-position: 80px 0px;
    background-size: 100% 110vh;
    height: 100%;
    width: 100%;
}
.wrapper {
    position: relative;


}

.cont {
    display: none;
}


.masonry {
    position: relative;
    // padding: 0;
    width: 90%;
    left: 5%;
    -moz-column-gap: 1.5em;
    -webkit-column-gap: 1.5em;
    column-gap: 1.5em;
    font-size: .85em;

}

.item {
    display: inline-block;
    position: relative;
    z-index: 1;
    margin-top: 20px;
         background: rgba(34, 34, 34, 0.576);
  
    
}


.centered{
    position: absolute;
    top: 0%;
    left: -22vmin;
     margin-right: -50%;
    transform: translate(-50%, -50%);
    font-size: 3vmin;
    // width: 100%;
    color: white;
    cursor: pointer;
    text-align: center;
    
}


@media only screen and (min-width: 300px) {
    .masonry {
        -moz-column-count: 2;
        -webkit-column-count: 2;
        column-count: 2;
    }
}

@media only screen and (min-width: 700px) {
    .masonry {
        -moz-column-count: 3;
        -webkit-column-count: 3;
        column-count: 3;
    }
}

@media only screen and (min-width: 900px) {
    .masonry {
        -moz-column-count: 4;
        -webkit-column-count: 4;
        column-count: 4;
    }
}

@media only screen and (min-width: 1100px) {
    .masonry {
        -moz-column-count: 4;
        -webkit-column-count: 4;
        column-count: 4;
    }
}

@media only screen and (min-width: 1280px) {
    .wrapper {
        // width: 1260px;
    }
}

        .v-img {
            
            max-height: 100%;
            max-width: 100%;
            opacity: .5;
       
            transition: opacity .3s;
            filter: blur(1px);
            cursor: pointer;
            z-index: 0;
            
        }
        .v-img:hover {
            opacity: 1;
            filter: blur(0px);
           
        }
    }
  .modalImage {
        position: fixed;
            top: 0;
            left: 0;
            bottom: 0;
            right: 0;
            background: $gradient-opacity;
            z-index: 9;
  
  }

.modalImages {
    padding: 0;
    margin-top: 40px;
    // margin: 0 auto;
    

    img {
        // width: 50vw;
        max-height: 95%;
        top: 50%;
        left: 50%;
        position: absolute;
        transform: translate(-50%, -50%);
      
   
    }

}

.closeImage {
    position: absolute;
    top: 10%;
    right: 5%;
    transform: translate(-50%, -50%);
    font-size: 70px;
    z-index: 9999;
    color:white;
    font-weight: 600;
    cursor: pointer;
}


    @media screen and (max-width: 748px) {
           #gallery {
        margin-top: 70px;
        }

          .v-img {
            opacity: 1!important;
              filter: blur(0px)!important;
              
        }

        .closeImage {
            font-size: 50px;
            top: 5%;
            right: 0%;
        }

                
        .modalImages {
            padding: 0;
            margin-top: 40px;
            // margin: 0 auto;
    

        img {
            // width: 50vw;
            max-width: 95%;
            top: 50%;
            left: 50%;
            position: absolute;
            transform: translate(-50%, -50%);
        
    
        }

        }
    }
    

</style>



