<template>
  <div id="welcome" >
     <section class="welcome">

       <div class="container">

      
       <div class="wel-back row">
 
      


             <div class="col-sm-5 col-xs-12">
          <ul class='circle-container'>
              <button class="tablinks active" id="tab1" v-on:click="selectTab(1)"><i class="fa fa-handshake-o fa-4x" data-fa-transform="shrink-1 down-1"></i></button>
              <button class="tablinks" id="tab2" v-on:click="selectTab(2)"><i class="fa fa-users fa-4x " data-fa-transform="shrink-1 "></i></button>
              <button class="tablinks" id="tab3" v-on:click="selectTab(3)"><octicon name="globe" scale="5"></octicon></button>
              <button class="tablinks" id="tab4" v-on:click="selectTab(4)"><i class="fa fa-book fa-4x " data-fa-transform="shrink-1"></i></button>
              <button class="tablinks" id="tab5" v-on:click="selectTab(5)"><img class="fish-icon" src="../../assets/img/icons/fish-icon.svg" alt=""></button>
          </ul>
       </div>

              <div class="col-sm-7 col-xs-12">
          <div id="tab1Content" class="tabcontent ">  
            <img src="../../assets/img/texts/bien.png" alt=""><br>
            <p>{{bienText}}Contrary to popular belief, Lorem Ipsum is not simply random text. It has roots in a piece of classical Latin literature from 45 BC, making it over 2000 years old. Richard McClintock, a Latin professor at Hampden-Sydney College in Virginia, looked up one of the more obscure Latin words, consectetur, from a Lorem Ipsum passage, and going through the cites of the word in classical literature, discovered the undoubtable source. Lorem Ipsum comes from sections 1.10.32 and 1.10.33 of "de Finibus Bonorum et Malorum" (The Extremes of Good and Evil) by Cicero, written in 45 BC. This book is a treatise on the theory of ethics, very popular during the Renaissance. The first line of Lorem Ipsum, "Lorem ipsum dolor sit amet..", comes from a line in section 1.10.32.
The standard chunk of Lorem Ipsum used since the 1500s is reproduced below for those interested. Sections 1.10.32 and 1.10.33 from "de Finibus Bonorum et Malorum" by Cicero are also reproduced in their exact original form, accompanied by English versions from the 1914 translation by H. Rackham.</p>
          </div>
          <div id="tab2Content" class="tabcontent ">
            <h3>Paris</h3>
            <p>Paris is the capital of France.</p> 
          </div>
          <div id="tab3Content" class="tabcontent ">
            <h3>asdf</h3>
            <p>Tokyo is the capital of Japan.</p>
          </div>
          <div id="tab4Content" class="tabcontent ">
            <h3>Tokyo</h3>
            <p>Tokyo is the capital of Japan.</p>
          </div>
          <div id="tab5Content" class="tabcontent ">
            <h3>hadfg</h3>
            <p>Tokyo is the capital of Japan.</p>
          </div>
       </div>
       </div>
       </div>
     </section>
   </div>
</template>

<script>
import Octicon from 'vue-octicon/components/Octicon.vue'
import 'vue-octicon/icons/globe'


export default {
  name: 'welcome',
  components: {
  Octicon
  },
   data(){
    return {
        bienText: ""
    }
   },
  methods: {
      buttonClick(){
        var hide = true;
    $('.tablinks').click(function(){

      var self = $(this);

      if (self.hasClass('active')) {
          $('.tablinks').removeClass('active');
          return false;
      }

      $('.tablinks').removeClass('active');

      self.toggleClass('active');
      hide = false;

    
    });

        },  
      selectTab(tabIndex) {
      //Hide All Tabs
      $("#tab1Content").css("display", "none");
      $("#tab2Content").css("display", "none");
      $("#tab3Content").css("display", "none");
      $("#tab4Content").css("display", "none");
      $("#tab5Content").css("display", "none");
      
      //Show the Selected Tab
        $("#tab"+ tabIndex +'Content').css("display", "block");
    }
  },
  mounted(){
 
   this.buttonClick();
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';
@import '../../assets/bootstrap.min';

.welcome {
    background: $gradient-2;
  height: 90vh;
  position: relative;
  z-index: 1;

  .wel-back {
    margin-top: -20px;
  }
}
#tab1Content {
 display: block; 
 
}

#tab2Content, #tab3Content, #tab4Content, #tab5Content  {

 display: none; 


}
.active {
  transform: scale(1.4)!important;
   filter: blur(0px) !important;
  // transform: rotate(189deg)!important;
}
.tablinks {
   filter: blur(3px);

   svg {
     color:white;
   }
   i {
     color:white;
   }
   .fish-icon {
     width: 70px;
     transform: rotate(90deg);
   }
}
.tabcontent {
  padding: 20px;
  padding-top: 100px;
  height: 80vh;
  color:white;
  p{
    color:white;
    width: 100%;
    padding: 0 0 0 100px;
    font-size: 1.05vw;
    
  }

  img{
    height: 70px;
    padding-left: 40px;
  }
}


@mixin on-circle($item-count, $circle-size, $item-size) {  
  position: relative;
  width:  $circle-size;
  height: $circle-size;
  border-radius: 50%;
  padding: 0; 
  list-style: none;
  
  > * {
    display: block;
    position: absolute;
    top:  50%; 
    left: 50%;
    margin: -($item-size / 2);
    width:  $item-size;
    height: $item-size;
  
    $angle: (360 / $item-count);
    $rot: 0;

    @for $i from 1 through $item-count {
      &:nth-of-type(#{$i}) {
        transform: rotate($rot * 1deg) translate($circle-size / 1.7) rotate($rot * -1deg);
      }

      $rot: $rot + $angle;
    }
  }
}

.circle-container {
  @include on-circle($item-count: 5, $circle-size: 18em, $item-size: 8em); 
  margin: 150px auto 0;
  border: dotted 5px white;

  button { 
    display: block; 
    border: white solid 6px;
    background: linear-gradient(45deg, #e47474 0%, rgb(120, 221, 255) 100%) no-repeat ;
    background-size: 120% 100%;
    max-width: 100%; 
    border-radius: 50%;
    transition: .5s;
    cursor: pointer;
     
    &:hover {
      filter: brightness(110%);
    }
  }
}







@media screen and (max-width: 748px) {

  .welcome {
  height: 100vh;

}

  .active {
  transform: scale(1.1)!important;
   filter: blur(0px) !important;
  }
.tablinks {
   filter: blur(3px);

   svg {
     color:white;
   }
   i {
     color:white;
     font-size: 9vw;
   }
   .fish-icon {
     width: 40px;
     transform: rotate(90deg);
   }

}

.octicon {
  transform: scale(.6);
}



  .tabcontent {
  padding: 20px;
  padding-top: 100px;
  height: 10vh;
  color:white;

  p{
    color:white;
    width: 100%;
    padding: 0 0 0 0px;
    font-size: 2.5vw;
    
  }

  img{
    height: 55px;
    padding-left: 40px;
  }
}



.circle-container {
  @include on-circle($item-count: 5, $circle-size: 12em, $item-size: 6em); 
  margin: 120px auto 0;
  border: dotted 5px white;

  button { 
    display: block; 
    border: white solid 6px;
    background: linear-gradient(45deg, #e47474 0%, rgb(120, 221, 255) 100%) no-repeat ;
    background-size: 120% 100%;
    max-width: 100%; 
    border-radius: 50%;
    transition: .5s;
    cursor: pointer;
     
    &:hover {
      filter: brightness(110%);
    }
  }
}


}


</style>



