<template>
  <div>
	<div class="limiter member">
		<div class="container-login100">
			<div class="wrap-login100">
				<form class="login100-form validate-form">
					<span class="login100-form-title">
						Contactanos!    
					</span>

                    <div class="divider"></div>

					<div class="wrap-input100 validate-input" data-validate="Name is required">
						<input class="input100" type="text" name="name" v-model="data.name">
						<span class="focus-input100" data-placeholder="NAME"></span>
					</div>

					<div class="wrap-input100 validate-input" data-validate = "Valid email is required: ex@abc.xyz">
						<input class="input100" type="text" name="email" v-model="data.email">
						<span class="focus-input100" data-placeholder="EMAIL"></span>
					</div>

					<div class="wrap-input100 validate-input" data-validate = "Message is required">
						<textarea class="input100" name="message" v-model="data.message"></textarea>
						<span class="focus-input100" data-placeholder="MESSAGE"></span>
					</div>

					<div class="container-login100-form-btn">
						<div class="wrap-login100-form-btn">
							<div class="login100-form-bgbtn"></div>
							<button class="login100-form-btn" @click="sendMail()">
								Send Your Message
							</button>
						</div>
					</div>
				</form>
			</div>
		</div>
	</div>

  </div>
</template>

<script>
export default {
  name: 'Contact',
  data(){
    return {
      data:{
        name: "",
        email: "",
        message: ""
      }
      
    }
  },
   methods:{
      inputValue(){
             $('.input100').each(function(){
        $(this).on('blur', function(){
            if($(this).val().trim() != "") {
                $(this).addClass('has-val');
            }
            else {
                $(this).removeClass('has-val');
            }
        })    
    })
      },
      sendMail(){
        this.$http.post("http://iglesiadecristoenelgin.com/contact.php", {name: this.name, email: this.email, message: this.message})
        .then(response => {
            console.log(response);
        }).catch(error => {
      console.log(error);
  });
  }

  },
  mounted(){
      this.inputValue();
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>


@import '../assets/main';
@import '../assets/bootstrap.min';

.divider {
    position: relative;
    height: 4px;
    width: 100%;
    left: -10px;
    opacity: .9;
    z-index: 1;
    background: $gradient-2;
    transition: all .7s;
    border-radius: 10px;
    opacity: .7;
    margin: 20px;
}

.wrap-login100 {
  width: 70%;
  height: 95vh;
 

}

textarea.input100 {
  min-height: 150px;
  padding-top: 13px;
  padding-bottom: 13px;
}
textarea.input100 + .focus-input100::after {
  top: 16px;
  left: 0;
}

@media screen and (max-width: 748px) {
  .wrap-login100 {
     width: 100%;
     height: 90vh;
     padding: 77px 25px 13px 25px;
  }


  .input100 {
    font-size: 12px;
  }

  .divider {
      left: -15px;
  }
}


</style>



