<template>
  <div id="controls">
      <div class="audio_player container">
           <div class="row all-buttons">
                <div class="col-sm-2 col-xs-2"><button id="prevbtn"><i class="fa control-buttons fa-arrow-circle-left"></i></button></div>
                <div class="col-sm-2 col-xs-2"><button id="playbtn"><i class="fa control-buttons fa-play-circle-o"></i></button><button class="hide" id="pausebtn"> <i class="fa control-buttons fa-pause-circle-o"></i></button></div>
                <div class="col-sm-2 col-xs-2"><button id="nextbtn"><i class="fa control-buttons fa-arrow-circle-right"></i></button></div>
                <div class="col-sm-2 col-xs-2"><button id="mutebtnon"  class="hide"><i class="fa  control-buttons fa-volume-off "> </i> <i class="fa fa-minus" aria-hidden="true"></i></button><button id="mutebtn"><i class="fa control-buttons fa-volume-up"></i></button></div>
                <div class="col-sm-2 col-xs-2"><input id="volumeslider" type="range" min="0" max="100" value="100" step="1"></div>
           </div>
      
        </div>
  </div>
</template>

<script>
export default {
  name: 'playercontrols',
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../../assets/main';
@import '../../assets/bootstrap.min';

    #controls {
        position: fixed;
        bottom: 0;
        height: 80px;
        background: $gradient-2;
        width: 100%;
        left: 0px;
        padding-left: 20%;

        .control-buttons {
            font-size: 4vw;
            color: white;
        }
    }

    .fa-play-circle-o, .fa-pause-circle-o, .fa-volume-up, .fa-volume-off, .fa-minus {
        position: absolute;
        text-shadow: -4px 4px 2px rgba(34, 34, 34, 0.349);
        top:0px;
        left: 10%;
    }

    .fa-arrow-circle-right, .fa-arrow-circle-left {
        text-shadow: -4px 4px 2px rgba(34, 34, 34, 0.349);

    }
   .fa-minus{
       top: 15px;
       left: 80px;  
       color:white;
       font-size: 3vw;
       
   }

    input#volumeslider{
                top: 30px;
                position: relative;
            }
           
            input[type='range'] {
                -webkit-appearance: none !important;
                margin:0px;
                padding:0px;
                background: #222;
                height:13px;
                 width: 17vw;
                border-radius: 50px;
                border-bottom:black 1px solid;
            }
            input[type='range']::-ms-fill-lower  {
                background:#000;
            }
            input[type='range']::-ms-fill-upper  {
                background:#000;
            }
            input[type='range']::-moz-range-track {
                border:none;
                background: #000;
               
            }
            input[type='range']::-webkit-slider-thumb {
                -webkit-appearance: none !important;
                background: white;
                height:20px;
                width:20px;
                border-radius:100%;
                cursor:pointer;
            }
            input[type='range']::-moz-range-thumb {
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:100%;
                cursor:pointer;
            }
            input[type='range']::-ms-thumb {
                -webkit-appearance: none !important;
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:100%;
                cursor:pointer;
            }


    .hide {
        display: none;
    }

@media screen and (max-width: 748px) {

    
    #controls {
        padding-left: 5%;
        
        .all-buttons {
            top: 15px;
            padding-top: 5px;
            position: relative;
        }

        .control-buttons {
            font-size: 10vw;
            color: white;
            
        }
    }

    .fa-play-circle-o, .fa-pause-circle-o, .fa-volume-up, .fa-volume-off, .fa-minus {
        top:0px;
        left: 30%;

    }
   .fa-minus{
       top: 15px;
       left: 70%;  
       color:white;
       font-size: 3vw;
       
   }

   
    input#volumeslider{
                top: -25px;
                position: absolute;
                left: -432%;
            }
           
            input[type='range'] {
                -webkit-appearance: none !important;
                margin:0px;
                padding:0px;
                background: white;
                height:13px;
                 width: 100vw;
                border-radius: 0px;
                border-bottom:white 1px solid;
            }
                 input[type='range']::-webkit-slider-thumb {
                -webkit-appearance: none !important;
                background: white;
                height:25px;
                width:25px;
                border-radius:100%;
                cursor:pointer;
                 -webkit-box-shadow: 2px 2px 5px 2px rgb(0, 0, 0);
                -moz-box-shadow: 2px 2px 5px 2px rgb(0, 0, 0);
                box-shadow: 2px 2px 1px 1px rgba(0, 0, 0, 0.37);
            }


}
</style>



