// Need to make data dymanic so ricardo can change series and picture

<template>
     <div id="topic">
         <div class="parallax hidden-xs"></div>
         <div class="parallax-mobile visible-xs"></div>
        <img class="img-title center" src="../../assets/img/texts/dias.png" alt=""><br>
            <div class="wrapper container">
                <div class="box col-sm-3" v-for="day in days" @click="clickedDay(day); showingModal = true;">
                    <div class="day">
                           <img :src="day.img"><br>
                            <div class="divider"></div><br>
                         <h4>{{day.time}}</h4>
                    </div>
                    
                </div>
            </div>

            <transition name="slide-fade">
               <div class="modall" id="addModal" v-if="showingModal" >
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="showingModal = false;">
                            &times;
                        </div>
                        <div class="modalContent" :style="{ 'background-image': 'url(' + dayClicked.dayImg + ')'}">
                            <!-- <img :src="dayClicked.dayImg"> -->
                                <h4> {{dayClicked.text}}</h4>
                        </div>
                    </div>
                </div>
            </div>
            </transition>
        
     </div>
</template>

<script>
export default {
  name: 'topics',
  data(){
      return {
          days: [
              { img: require('../../assets/img/texts/lunes.png'), time: '7-8 PM', dayImg: 'https://source.unsplash.com/VRr9a2rOoBI', text: "Lunes"},
              { img: require('../../assets/img/texts/mier.png'), time: '7-8 PM', dayImg: 'https://source.unsplash.com/lLk1oJA7Wkg', text: "Miercoles"},
              { img: require( '../../assets/img/texts/dom-am.png'), time: '9:30-11 AM', dayImg: 'https://source.unsplash.com/YS3Q5vroxtg', text: "Domingo AM"},
              { img: require( '../../assets/img/texts/dom-pm.png'), time: '3-4 PM' ,dayImg: 'https://source.unsplash.com/t1QUoAMyXDs', text: "Domingo PM"},
            ],
            dayClicked: {},
            showingModal: false
      }
  },
  methods: {
      clickedDay(day){
          this.dayClicked = day;
          console.log("day clicked")
          console.log(day);
      }
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../../assets/main';
@import '../../assets/bootstrap.min';


#topic {
    background: #222;
    height: 100vh;
    padding-top: 30px;

}
.wrapper {
    margin-top: 0px;
    height: 45vh;

}
.parallax {
    background-image: url('../../assets/img/intro/visitback.jpg');
    background-repeat: no-repeat;
    position: absolute;
    z-index: 0;
    left: 0;
    opacity: .4;
    margin-top: -100px;
    background-attachment: fixed;
    background-position: 80px 0px;
    background-size: 100% auto;
    height: 100%;
    width: 100%;
}

.divider {
    position: absolute;
    height: 6px;
    width: 80%;
    opacity: .9;
    border-radius: 10px;
    background: $gradient-2;
    transition: all .7s;
}

    .img-title {
        width: 40vw;
        position: relative;
        padding-top: 300px;
        margin-bottom: -100px; 
    }
    .day {
        padding: 35px 10px 35px 10px;
        text-align: center;
        color: white;
        transition: all 1s;
        // background: linear-gradient(90deg, rgb(46, 89, 102)  0%, rgb(92, 173, 201) 95%,  #d46e6e 5%);
        
        img {
            height: 55px;
            z-index: 1;
            position: relative;
            
        }
        h4{
            font-size: 2.5vw;
            margin: 0;
            position: relative;
            
        }
    }

.box {
    height: 200px;
    cursor: pointer;
    z-index: 1;
    opacity: .8;
    border-radius: 10px;
    transition: background-color 0.2s linear;
    
}
.box:hover {
    opacity: 1;
    background-color: #222;
    
        .divider {
            height: 90%;
            width: 90%;
            margin-top: -80px;
            margin-left: -10px;
            transition: all .7s;
            z-index: 0;
            background: $gradient-2;
            
        }
   
}

.fading{
  -webkit-animation-name: fading;
  -webkit-animation-duration: 1.8s;
  animation-name: fading;
  animation-duration: 1.8s;
}

@-webkit-keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}

@keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}


@media screen and (max-width: 748px) {

    #topics {
        height: 100vh;
    }

   .img-title {
        width: 80vw;
        position: relative;
        padding-top: 250px;
        margin-bottom: -110px; 
    }

    .parallax-mobile {
    background-image: url('../../assets/img/intro/banner.png');
    background-repeat: no-repeat;
    position: absolute;
    z-index: 0;
    left: 0;
    opacity: .4;
    margin-top: 0px;
    background-attachment: fixed;
    background-position: 70% 0px;
    background-size: 300% auto;
    height: 100%;
    width: 100%;
}

.wrapper {
    margin-top: -30px;
    height: 45vh;

}

    .day {
        
        img {
            height: 45px;
            z-index: 1;
            position: relative;
            
        }
        h4{
            font-size: 6vw;
            margin: 0;
            position: relative;
            
        }
    }

.box {
    height: 120px;
    cursor: pointer;
    z-index: 1;
    opacity: .8;
    border-radius: 10px;
    transition: background-color 0.2s linear;
    
}

}


</style>



