<template>
  <div>

    <scrollactive class="my-nav" ref="scrollactive" :offset="0"
      :duration="800"
      bezier-easing-value=".5,0,.35,1">
      <a href="#intro" class="scrollactive-item">Intro</a>
      <a href="#welcome" class="scrollactive-item">Bienvenida</a>
      <a href="#topics" class="scrollactive-item">Horario</a>
      <a href="#evang" class="scrollactive-item">Evangelio</a>
      <a href="#preacher" class="scrollactive-item">Predicador</a>
      <a href="#mission" class="scrollactive-item">Missiones</a>
      <a href="#team" class="scrollactive-item">Equipo</a>
      <a href="#groups" class="scrollactive-item">Groupos</a>

  </scrollactive>
  </div>
</template>

<script>

export default {
  name: 'scrollspy'
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';


// fixed side navigation with dots
.my-nav{
  position: fixed;
  height: 35px;
  bottom:0px;
  width: 100%;
  z-index: 99999;
  text-align: center;
  transition: all .3s;
  background: rgba(87, 86, 86, 0.885);


  a{
    text-decoration: none;
    font-size: 1vw;
    color: white;
    padding-right: 5vw;
    
  }
  a:hover {
    font-weight: 500;
  }

  .is-active {
    font-weight: 700;
    background: $gradient-2;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-size: 100px;
    line-height: 35px;
}
  
}

.my-nav:hover {

}

</style>



